    try:
        databases = view._non_atomic_requests | {using}
    except AttributeError:
        databases = {using}

    @wraps(view)
    def wrapper(*args, **kwargs):
        return view(*args, **kwargs)

    wrapper._non_atomic_requests = databases
    return wrapper


